import React, { useState } from 'react';
import Sidebar from './../components/Sidebar';

function ProjectPage() {
  return (
    <div>
      <Sidebar />
        <Spring
        from={{ opacity: 0, marginRight: -70 }}
        to={{ opacity: 1, marginRight: 0 }}
        >
          {props => (
            <div style={props}>
                <h1>asdasd</h1>
            </div>
          )}
        </Spring>
    </div>
  );
}

export default ProjectPage;
